return {
&quot;risk_level&quot;: risk_level,
&quot;issues&quot;: issues,
&quot;recommendation&quot;: &quot;建议使用同义词替换局部重复词汇&quot; if issues else &quot;文本词汇多样性良好&quot;
}
def generate_report(self, result: Dict) -&gt; str:
&quot;&quot;&quot;生成可读性报告&quot;&quot;&quot;
report = []
report.append(&quot;=&quot; * 60)
report.append(&quot;词汇重复检测报告&quot;)
report.append(&quot;=&quot; * 60)
report.append(f&quot;文本长度：{result['text_length']} 词&quot;)
report.append(f&quot;内容词数量：{result['content_words']} 词&quot;)
report.append(f&quot;词汇丰富度评分：{result['lexical_richness_score']}/100&quot;)
report.append(&quot;&quot;)
if result['high_frequency_words']:
report.append(&quot;高频词统计：&quot;)
for word, freq in sorted(result['high_frequency_words'].items(),
key=lambda x: x[1], reverse=True)[:10]:
report.append(f&quot;  '{word}': 出现{freq}次&quot;)
if result['local_repetitions']:
report.append(&quot;\n局部重复检测（滑动窗口内出现3次以上）：&quot;)
for rep in result['local_repetitions'][:5]:  # 只显示前5个
report.append(f&quot;  词汇'{rep['word']}'在位置{rep['window_start']}-{rep['window_end']}出现{rep['frequency']}次&quot;)
if result['suggestions']:
report.append(&quot;\n替换建议：&quot;)
for word, info in result['suggestions'].items():
report.append(f&quot;  '{word}'（出现{info['frequency']}次，占比{info['repetition_rate']:.2f}%）&quot;)
report.append(f&quot;    可替换为：{', '.join(info['suggestions'])}&quot;)
report.append(f&quot;\n风险评估：{result['risk_assessment']['risk_level']}&quot;)
if result['risk_assessment']['issues']:
report.append(&quot;主要问题：&quot;)
for issue in result['risk_assessment']['issues']:
report.append(f&quot;  • {issue}&quot;)
report.append(f&quot;处理建议：{result['risk_assessment']['recommendation']}&quot;)
return &quot;\n&quot;.join(report)

